import { test, expect } from '@playwright/test';
import path from 'path';

test.use({ headless: false });

test('App Healing: Should fix broken button ID in the application source', async ({ page }) => {
    test.use({ headless: true });
  const filePath = `file://${path.resolve(process.cwd(), 'tests/target-app/login.html')}`;
  await page.goto(filePath);

  // The application currently has a 'typo' in its ID (super-secure-login-buttonn)
  // But our test is correctly written for what the code SHOULD be:
  await page.locator('#super-secure-login-button').click();
  
  await expect(page).toHaveURL(/dashboard.html/);
});
